#include<cstdio>
#include<algorithm>
#include<map>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
inline char Get(){char c;do c=getchar();while(c!='Q'&&c!='L');return c;}
const int N=8e4+10;int head[N],des[N<<1],nxt[N<<1],cgt,n,Q,m,lst;
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
struct Seg{int l,r,sm;}t[N<<11];int Rt[N],cnt,P[N],p,a[N];
inline int bnd(const int &k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int rt[N],fa[N],siz[N],mxs[N],top[N],dep[N],cdt,tot[N];bool debug=false;
inline void update(const int &x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm;}
std::map<int,bool> vs[N];
inline void add(int cur,int &x,const int &pos,const int &l=1,const int &r=p)
{
//	puts("add");
//	if(cnt>2217560)printf("add %d %d\n",l,r);
	t[x=++cnt]=t[cur];if(l==r){++t[x].sm;return;} const int &mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);update(x);
}
inline int qry(const int &u,const int &v,const int &c,const int &f,const int &k,const int &l=1,const int &r=p)
{	
	if(l==r)return P[l];const int &mid=(l+r)>>1,&lsz=t[t[u].l].sm+t[t[v].l].sm-t[t[c].l].sm-t[t[f].l].sm;
	return k<=lsz?qry(t[u].l,t[v].l,t[c].l,t[f].l,k,l,mid):qry(t[u].r,t[v].r,t[c].r,t[f].r,k-lsz,mid+1,r);
}
inline void dfs1(const int &u,const int &f)
{
	siz[u]=1;dep[u]=dep[fa[u]=f]+1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u,const int &fa,const int &tp)
{
	top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
}
inline int LCA(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u] < dep[v] ? u : v ;
}
bool vis[N];
inline void dfs3(const int &u,const int &f,const int &RT)
{
	rt[u]=RT;siz[u]=1;top[u]=u;dep[u]=dep[fa[u]=f]+1;mxs[u]=0;
	add(Rt[f],Rt[u],a[u]);grep(u,i)if(des[i]!=f){int v=des[i];dfs3(v,u,RT);}
}
inline void Lnk(int u,int v)
{
	if(siz[rt[u]]<siz[rt[v]]){int tmp(u);u=v;v=tmp;}
	
	tot[rt[u]]+=siz[rt[v]];siz[rt[u]]+=siz[rt[v]];
	dfs3(v,u,rt[u]);ins(u,v);
	if(tot[rt[u]]>255){dfs1(rt[u],0);dfs2(rt[u],0,rt[u]);tot[rt[u]]=0;}
}
inline void Qry(const int &k,const int &u,const int &v){int lc=LCA(u,v);printf("%d\n",lst=qry(Rt[u],Rt[v],Rt[lc],Rt[fa[lc]],k));fflush(stdout);}
int main()
{
//	FIN("P3302_3.in");FOUT("qwq.out");
	read();n=read();m=read();Q=read();rep(1,n,i)P[i]=a[i]=read();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	rep(1,n,i)rt[i]=top[i]=i,siz[i]=dep[i]=1,add(Rt[0],Rt[i],a[i]);
	int Cnt=0;
	while(m--)
	{
		int u=read(),v=read();if(u<v){int tmp(u);u=v;v=tmp;}
//		if(v==7268&&u==63054)++Cnt;if(Cnt>1)return 114514;
//		printf("%d\n",Cnt);
		if(!vs[u].count(v))Lnk(u,v),vs[u][v]=true;
	}
	while(Q--)switch(Get())
	{
		case 'L':Lnk(read()^lst,read()^lst);break;
		case 'Q':Qry(read()^lst,read()^lst,read()^lst);break;
	}
}
